import{_ as a,o as i,a as t,aI as r}from"./chunks/framework.CYBiNvwM.js";const S=JSON.parse('{"title":"浏览器内核的理解","description":"","frontmatter":{},"headers":[],"relativePath":"浏览器/浏览器内核的理解.md","filePath":"浏览器/浏览器内核的理解.md","lastUpdated":1774969370000}'),l={name:"浏览器/浏览器内核的理解.md"};function o(p,e,n,_,s,d){return i(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="浏览器内核的理解" tabindex="-1">浏览器内核的理解 <a class="header-anchor" href="#浏览器内核的理解" aria-label="Permalink to &quot;浏览器内核的理解&quot;">​</a></h1><ul><li><p>主要分成两部分：渲染引擎（Layout Engine 或 Rendering Engine）和 JS 引擎</p></li><li><p>渲染引擎：负责获取网页的内容（HTML、XML、图像等）、解析内容并应用样式信息（例如 CSS），以及计算网页的布局和显示方式，最后将结果输出至显示器或打印机。不同浏览器的内核对于网页语法的解释可能存在差异，因此渲染效果也可能不同。所有网页浏览器、电子邮件客户端以及其他需要呈现网络内容的应用程序都需要内核支持。</p></li><li><p>JS 引擎：负责解析和执行 JavaScript 代码，以实现网页的动态交互效果。</p></li><li><p>最初，渲染引擎和 JS 引擎的区分并不十分明确，后来随着 JS 引擎功能日益独立和复杂，现在“浏览器内核”一词通常倾向于特指渲染引擎。</p></li></ul><p><strong>常见的浏览器内核有哪些</strong></p><ul><li><p>Trident 内核：IE 浏览器（现已由 Microsoft Edge 替代），以及早期一些国产浏览器如 360、搜狗等曾采用该内核。[又称 MSHTML，目前该内核已基本停止更新]</p></li><li><p>Gecko 内核：Netscape 6 及以上版本，Firefox（FF），Mozilla Suite / SeaMonkey 等。[Firefox 至今仍主要使用该内核]</p></li><li><p>Presto 内核：Opera 7 至 12 版本使用。[Opera 浏览器现已转向使用 Blink 内核]</p></li><li><p>WebKit 内核：Safari，早期版本的 Chrome 等。[Chrome 及后续的 Edge、Opera 等现代浏览器目前主要采用 Blink 内核（由 WebKit 分支发展而来）]</p></li></ul>',4)])])}const f=a(l,[["render",o]]);export{S as __pageData,f as default};
